sys_script.script:
(function executeRule(current, previous /*null when async*/ ) {

    // ================================
    // 1. Check dependency in lookup rules
    // ================================
    var lookupRule = new GlideRecord('x_ctans_incentnow_lookup_rule');
    lookupRule.addQuery('select_previous_step', current.sys_id);
    lookupRule.query();

    if (lookupRule.next()) {
        gs.addErrorMessage(
            "Cannot delete. This step is used by lookup rule: " +
            lookupRule.display_name
        );
        current.setAbortAction(true);
        return;
    }

    // ================================
    // 2. Check dependency in payout summary (Input 1)
    // ================================
    var payout1 = new GlideRecord('x_ctans_incentnow_payout_summary');
    payout1.addQuery('input1_type', 'data_step');
    payout1.addQuery('input1_id', current.sys_id);
    payout1.query();

    if (payout1.next()) {
        gs.addErrorMessage(
            "Cannot delete. This step is used in payout rule (Input 1): " +
            payout1.rule_name
        );
        current.setAbortAction(true);
        return;
    }

    // ================================
    // 3. Check dependency in payout summary (Input 2)
    // ================================
    var payout2 = new GlideRecord('x_ctans_incentnow_payout_summary');
    payout2.addQuery('input2_type', 'data_step');
    payout2.addQuery('input2_id', current.sys_id);
    payout2.query();

    if (payout2.next()) {
        gs.addErrorMessage(
            "Cannot delete. This step is used in payout rule (Input 2): " +
            payout2.rule_name
        );
        current.setAbortAction(true);
        return;
    }

})(current, previous);
